730	// Heartbeat refreshes the external claim liveness lease on a claimed bead.
731	// Returns an error if the bead is no longer in_progress (e.g., reclaimed by
732	// another worker), allowing the caller to stop its heartbeat loop.
733	//
734	// Deprecated: use TouchClaimHeartbeat.
735	func (s *Store) Heartbeat(id string) error {
736		if err := s.WithLock(func() error {
737			beads, _, err := s.readAllLatestRaw()
738			if err != nil {
739				return err
740			}
741			for _, b := range beads {
742				if b.ID != id {
743					continue
744				}
745				if b.Status != StatusInProgress {
746					return fmt.Errorf("bead: cannot heartbeat %s from status %s", id, b.Status)
747				}
748				return s.TouchClaimHeartbeat(id)
749			}
750			return fmt.Errorf("bead: not found: %s", id)
751		}); err != nil {
752			return err
753		}
754		return nil
755	}
