757	// claimLeaseIsStale returns true if the external claim lease is absent or
758	// older than HeartbeatTTL. When no lease file exists, it falls back to the
759	// legacy execute-loop-heartbeat-at tracker field for compatibility.
760	func claimLeaseIsStale(s *Store, extra map[string]any, id string) bool {
761		if s != nil {
762			if fresh, found, err := s.ClaimHeartbeatFresh(id); err == nil {
763				if found {
764					return !fresh
765				}
766			} else {
767				return heartbeatIsStale(extra)
768			}
769		}
770		return heartbeatIsStale(extra)
771	}
772	
773	// heartbeatIsStale returns true if the given bead's Extra map has no
774	// execute-loop-heartbeat-at or one older than HeartbeatTTL.
775	func heartbeatIsStale(extra map[string]any) bool {
776		if extra == nil {
777			return true
778		}
779		raw, ok := extra["execute-loop-heartbeat-at"]
780		if !ok {
781			return true
782		}
783		s, ok := raw.(string)
784		if !ok || s == "" {
785			return true
786		}
787		t, err := time.Parse(time.RFC3339Nano, s)
788		if err != nil {
789			// Fall back to RFC3339 for compatibility with legacy entries written
790			// before sub-second resolution. RFC3339Nano is the current canonical
791			// format used by both ClaimWithOptions and Heartbeat write sites.
792			t, err = time.Parse(time.RFC3339, s)
793			if err != nil {
794				return true
795			}
796		}
797		return time.Since(t) > HeartbeatTTL
798	}
