800	// Unclaim clears claim metadata. Only reverts status to open if the bead
801	// is currently in_progress — a closed bead stays closed.
802	func (s *Store) Unclaim(id string) error {
803		if err := s.updateBead(id, true, func(b *Bead) error {
804			if b.Status == StatusInProgress {
805				if err := transitionLifecycleInPlace(b, StatusOpen, LifecycleTransitionOptions{
806					Reason: "unclaim",
807					Source: "Store.Unclaim",
808				}); err != nil {
809					return err
810				}
811			}
812			b.Owner = ""
813			if b.Extra != nil {
814				for _, k := range ClaimMetadataExtraKeys {
815					delete(b.Extra, k)
816				}
817				delete(b.Extra, ClaimHeartbeatExtraKey)
818			}
819			return nil
820		}); err != nil {
821			return err
822		}
823		return s.RemoveClaimHeartbeat(id)
824	}
