826	// SetExecutionCooldown parks bead id until the given wall-clock time.
827	// baseRev is the origin/main HEAD at cooldown time; when non-empty it enables
828	// rev-bound auto-invalidation: if origin/main advances past baseRev the
829	// cooldown clears automatically on the next ready-queue pass.
830	func (s *Store) SetExecutionCooldown(id string, until time.Time, status, detail, baseRev string) error {
831		return s.Update(id, func(b *Bead) {
832			if b.Extra == nil {
833				b.Extra = make(map[string]any)
834			}
835			b.Extra["execute-loop-retry-after"] = until.UTC().Format(time.RFC3339)
836			if status != "" {
837				b.Extra["execute-loop-last-status"] = status
838			}
839			if detail != "" {
840				b.Extra["execute-loop-last-detail"] = detail
841			}
842			if baseRev != "" {
843				b.Extra[ExtraCooldownBaseRev] = baseRev
844			} else {
845				delete(b.Extra, ExtraCooldownBaseRev)
846			}
847		})
848	}
849	
850	// ClearCooldowns clears execute-loop cooldown fields for all beads matched by
851	// filter. If filter is nil, every bead with execute-loop-retry-after set is
852	// cleared. Returns the count of beads whose cooldowns were cleared. A
853	// "cooldown-cleared" event with reason="operator-bulk-clear" is appended for
854	// each cleared bead in the same pass.
855	func (s *Store) ClearCooldowns(filter func(Bead) bool) (int, error) {
856		var count int
857		err := s.WithLock(func() error {
858			beads, _, err := s.readAllLatestRaw()
859			if err != nil {
860				return err
861			}
862			now := time.Now().UTC()
863			for i := range beads {
864				b := &beads[i]
865				if extraStringVal(b.Extra, ExtraRetryAfter) == "" {
866					continue
867				}
868				if filter != nil && !filter(*b) {
869					continue
870				}
871				if b.Extra == nil {
872					b.Extra = make(map[string]any)
873				}
874				delete(b.Extra, ExtraRetryAfter)
875				delete(b.Extra, ExtraCooldownBaseRev)
876				delete(b.Extra, ExtraLastStatus)
877				delete(b.Extra, ExtraLastDetail)
878				b.UpdatedAt = now
879				var events []BeadEvent
880				if raw, ok := b.Extra["events"]; ok {
881					events = decodeBeadEvents(raw)
882				}
883				events = append(events, BeadEvent{
884					Kind:      "cooldown-cleared",
885					Summary:   "operator-bulk-clear",
886					Source:    "ddx work clear-cooldowns",
887					CreatedAt: now,
888				})
889				b.Extra["events"] = encodeEventsForExtra(events)
890				if err := s.validateBead(b); err != nil {
891					return err
892				}
893				count++
894			}
895			if count == 0 {
896				return nil
897			}
898			return s.WriteAll(beads)
899		})
900		return count, err
901	}
