903	// IncrNoChangesCount increments the execute-loop no-changes counter for a bead
904	// and returns the new count. Used by the execute-bead worker to detect when a
905	// bead should be auto-closed after repeated no-change attempts.
906	func (s *Store) IncrNoChangesCount(id string) (int, error) {
907		var newCount int
908		err := s.Update(id, func(b *Bead) {
909			if b.Extra == nil {
910				b.Extra = make(map[string]any)
911			}
912			var count int
913			if v, ok := b.Extra["execute-loop-no-changes-count"]; ok {
914				switch n := v.(type) {
915				case int:
916					count = n
917				case float64:
918					count = int(n)
919				case int64:
920					count = int(n)
921				}
922			}
923			count++
924			b.Extra["execute-loop-no-changes-count"] = count
925			newCount = count
926		})
927		return newCount, err
928	}
929	
930	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
931	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
932	// DDx-authored beads always round-trip through `bd import`. Empirically
933	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
934	const MaxFieldBytes = 65535
935	
936	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
937	// need to preserve the full payload should persist it to a sidecar artifact
938	// and store a path reference in the field; this function is the defense-in-
939	// depth cap for code paths that don't. Returns the input unchanged when it
940	// fits; otherwise returns head+tail truncation with a byte-count marker.
941	func capFieldBytes(s string) string {
942		if len(s) <= MaxFieldBytes {
943			return s
944		}
945		// Reserve a marker that always fits; keep head heavy (2/3) so
946		// human-readable context is preserved for the common short-rationale case.
947		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
948		budget := MaxFieldBytes - len(marker)
949		if budget <= 0 {
950			return s[:MaxFieldBytes]
951		}
952		head := (budget * 2) / 3
953		tail := budget - head
954		return s[:head] + marker + s[len(s)-tail:]
955	}
956	
957	// Cancel-marker keys on Bead.Extra. ADR-022 §Cancel SLA: an operator-initiated
958	// cancel writes cancel-requested:true; the worker that honors the cancel writes
959	// cancel-honored:true alongside it.
960	const (
961		ExtraCancelRequested = "cancel-requested"
962		ExtraCancelHonored   = "cancel-honored"
963	)
964	
965	// RequestCancel writes Extra[cancel-requested]=true on the bead. Idempotent:
966	// if cancel-honored is already set the call is a silent no-op (the prior cancel
967	// was already consumed). Returns true when the marker is now set on the bead
968	// (either by this call or a prior one).
969	func (s *Store) RequestCancel(id string) (bool, error) {
970		var set bool
971		err := s.Update(id, func(b *Bead) {
972			if b.Extra == nil {
973				b.Extra = make(map[string]any)
974			}
975			if isExtraTrue(b.Extra[ExtraCancelHonored]) {
976				set = isExtraTrue(b.Extra[ExtraCancelRequested])
977				return
978			}
979			b.Extra[ExtraCancelRequested] = true
980			set = true
981		})
982		return set, err
983	}
984	
985	// IsCancelRequested reports whether the bead carries an unconsumed cancel
986	// marker (cancel-requested:true and cancel-honored not yet set).
987	func (s *Store) IsCancelRequested(id string) (bool, error) {
988		b, err := s.Get(id)
989		if err != nil {
990			return false, err
991		}
992		if b == nil || b.Extra == nil {
993			return false, nil
994		}
995		if isExtraTrue(b.Extra[ExtraCancelHonored]) {
996			return false, nil
997		}
998		return isExtraTrue(b.Extra[ExtraCancelRequested]), nil
999	}
