1022	func (s *Store) AppendEvent(id string, event BeadEvent) error {
1023		if event.CreatedAt.IsZero() {
1024			event.CreatedAt = time.Now().UTC()
1025		}
1026		// Defense in depth: cap every event body regardless of caller. The
1027		// reviewer write path separately persists the full stream to an artifact
1028		// and emits a <=512-byte body; this cap catches anything else.
1029		event.Body = capFieldBytes(event.Body)
1030		event.Summary = capFieldBytes(event.Summary)
1031		// Two storage shapes are possible here: inline Extra["events"] for active
1032		// beads, and a sidecar attachment for closed/archived beads (ADR-004
1033		// attachment model). When the bead has been externalized we append to the
1034		// sidecar and leave the row untouched aside from updated_at.
1035		var appendedToAttachment bool
1036		if err := s.Update(id, func(b *Bead) {
1037			if b.Extra == nil {
1038				b.Extra = make(map[string]any)
1039			}
1040			if hasEventsAttachment(b) {
1041				appendedToAttachment = true
1042				return
1043			}
1044			var events []BeadEvent
1045			if raw, ok := b.Extra["events"]; ok {
1046				events = decodeBeadEvents(raw)
1047			}
1048			events = append(events, event)
1049			b.Extra["events"] = encodeEventsForExtra(events)
1050		}); err != nil {
1051			return err
1052		}
1053		if !appendedToAttachment {
1054			return nil
1055		}
1056		// Append to the sidecar under the store lock so concurrent readers and
1057		// writers see a consistent events log.
1058		return s.WithLock(func() error {
1059			existing, err := s.readEventsAttachment(id)
1060			if err != nil {
1061				return err
1062			}
1063			existing = append(existing, event)
1064			return s.writeEventsAttachment(id, existing)
1065		})
1066	}
