1104	func decodeBeadEvents(raw any) []BeadEvent {
1105		switch v := raw.(type) {
1106		case []BeadEvent:
1107			out := make([]BeadEvent, len(v))
1108			copy(out, v)
1109			return out
1110		case []any:
1111			out := make([]BeadEvent, 0, len(v))
1112			for _, item := range v {
1113				m, ok := item.(map[string]any)
1114				if !ok {
1115					continue
1116				}
1117				out = append(out, beadEventFromMap(m))
1118			}
1119			return out
1120		case []map[string]any:
1121			out := make([]BeadEvent, 0, len(v))
1122			for _, item := range v {
1123				out = append(out, beadEventFromMap(item))
1124			}
1125			return out
1126		default:
1127			return nil
1128		}
1129	}
