1201	// ErrClosureGateRejected indicates a close was refused because the bead does
1202	// not carry the evidence required for an automated closure: a terminal
1203	// verdict event (review APPROVE with non-empty rationale, or an explicit
1204	// review-skipped / manual-close marker) AND an execution-evidence marker
1205	// (closing_commit_sha, session_id, or an execute-bead success event in the
1206	// events history).
1207	//
1208	// Automated execute-loop paths (execute-bead + reviewer) always go through
1209	// CloseWithEvidence. The plain Store.Close remains as the manual
1210	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
1211	// acceptance §1).
1212	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
1213	
1214	// ClosureGate inspects a bead and returns nil iff the close is safe. It
1215	// rejects only the specific shapes that caused the 2026-04-18/20
1216	// review-malfunction incidents:
1217	//
1218	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
1219	//     closing_commit_sha. Rejected by the execution-evidence check —
1220	//     closing_commit_sha must be non-empty OR at least one event must exist.
1221	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
1222	//     body is empty. Rejected — APPROVE with no rationale is exactly the
1223	//     parse-mis-extract shape the reviewer bug produced.
1224	//
1225	// Beads without a review step (--no-review, no Reviewer configured, already-
1226	// satisfied paths) pass the gate as long as they carry execution evidence.
1227	// This keeps the surface small: the gate catches known-bad shapes, not every
1228	// conceivable edge case. Additional invariants belong in future dedicated
1229	// beads so the rejection reason stays auditable.
1230	func ClosureGate(b *Bead) error {
1231		if b == nil {
1232			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
1233		}
1234		hasClosingCommit := false
1235		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
1236			hasClosingCommit = true
1237		}
1238		events := decodeBeadEvents(b.Extra["events"])
1239		// Externalized events still count as evidence for the gate. We only need
1240		// to know whether *some* event history exists, not iterate it; the
1241		// gate's APPROVE-with-empty-rationale check below relies on inline events
1242		// (the verdict is recorded before externalization).
1243		hasAttachedEvents := hasEventsAttachment(b)
1244		// Reject the axon-c5cc071a shape: no events AND no closing commit.
1245		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
1246			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
1247		}
1248		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
1249		for _, e := range events {
1250			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
1251				if strings.TrimSpace(e.Body) == "" {
1252					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
1253				}
1254			}
1255		}
1256		return nil
1257	}
