1576	// activeRetryCooldown returns the retry-after time and whether the cooldown is
1577	// still active for bead b. When execute-loop-cooldown-base-rev is set and
1578	// originHead has advanced past that rev (i.e., originHead != baseRev and both
1579	// are non-empty), the cooldown auto-clears regardless of wall-clock expiry —
1580	// the world-state that caused the cooldown has changed. See TD-031 §5 invariant.
1581	// originHead should be the current origin/main HEAD, read once per
1582	// ready-queue evaluation pass (not per bead).
1583	func activeRetryCooldown(b Bead, now time.Time, originHead string) (time.Time, bool) {
1584		retryAfterStr := extraStringVal(b.Extra, ExtraRetryAfter)
1585		if retryAfterStr == "" {
1586			return time.Time{}, false
1587		}
1588		retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1589		if err != nil {
1590			return time.Time{}, false
1591		}
1592		// Rev-bound auto-invalidation: if origin/main has advanced since this
1593		// cooldown was set, the fix may already be in and the cooldown should clear.
1594		baseRev := extraStringVal(b.Extra, ExtraCooldownBaseRev)
1595		if baseRev != "" && originHead != "" && originHead != baseRev {
1596			return time.Time{}, false
1597		}
1598		return retryAfter, retryAfter.After(now)
1599	}
