1786	func isHumanReviewBlocker(b Bead) bool {
1787		// Post-lifecycle: proposed status is the canonical operator-attention signal.
1788		if b.Status == StatusProposed {
1789			return true
1790		}
1791		// Legacy: open beads with investigation/human-review labels still count.
1792		if b.Status != StatusOpen {
1793			return false
1794		}
1795		for _, label := range b.Labels {
1796			switch label {
1797			case LabelNeedsHuman, LabelNeedsInvestigation, LabelNoChangesUnverified, LabelNoChangesUnjustified:
1798				return true
1799			}
1800		}
1801		return false
1802	}
