1936					},
1937				})
1938			case LifecycleBucketNotEligible:
1939				entries = append(entries, BlockedBead{
1940					Bead: entry.Bead,
1941					Blocker: Blocker{
1942						Kind:   BlockerKindNotEligible,
1943						Reason: entry.ExecutionSkipReason,
1944					},
1945				})
1946			case LifecycleBucketSuperseded:
1947				entries = append(entries, BlockedBead{
1948					Bead: entry.Bead,
1949					Blocker: Blocker{
1950						Kind:   BlockerKindSuperseded,
1951						Reason: entry.SupersededBy,
1952					},
1953				})
1954			case LifecycleBucketRetryCooldown:
1955				entries = append(entries, BlockedBead{
1956					Bead: entry.Bead,
1957					Blocker: Blocker{
1958						Kind:           BlockerKindRetryCooldown,
1959						NextEligibleAt: entry.RetryAfter.UTC().Format(time.RFC3339),
1960						LastStatus:     entry.LastStatus,
1961						LastDetail:     entry.LastDetail,
1962					},
1963				})
1964			}
1965		}
1966	
1967		sort.SliceStable(entries, func(i, j int) bool {
1968			if entries[i].Priority != entries[j].Priority {
1969				return entries[i].Priority < entries[j].Priority
1970			}
1971			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1972				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1973			}
1974			return entries[i].ID < entries[j].ID
1975		})
1976		return entries, nil
1977	}
