69		// First decode into a generic shape so we can validate the verdict
70		// field's presence and value before binding to ReviewVerdict.
71		var probe map[string]json.RawMessage
72		if err := json.Unmarshal([]byte(candidate), &probe); err != nil {
73			return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
74		}
75		rawVerdict, ok := probe["verdict"]
76		if !ok {
77			return ReviewVerdict{}, fmt.Errorf("%w: missing verdict field", ErrReviewVerdictUnparseable)
78		}
79		var verdictStr string
80		if err := json.Unmarshal(rawVerdict, &verdictStr); err != nil {
81			return ReviewVerdict{}, fmt.Errorf("%w: verdict not a string: %v", ErrReviewVerdictUnparseable, err)
82		}
83		switch Verdict(verdictStr) {
84		case VerdictApprove, VerdictRequestChanges, VerdictBlock, VerdictRequestClarification:
85		default:
86			return ReviewVerdict{}, fmt.Errorf("%w: unknown verdict %q", ErrReviewVerdictUnparseable, verdictStr)
87		}
88	
89		var rv ReviewVerdict
90		if err := json.Unmarshal([]byte(candidate), &rv); err != nil {
91			return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
92		}
93		return rv, nil
