266	func analyzeParseSince(s string) (time.Duration, error) {
267		if len(s) < 2 {
268			return 0, fmt.Errorf("invalid --since %q: use e.g. 7d, 2w, 1m", s)
269		}
270		n, err := strconv.Atoi(s[:len(s)-1])
271		if err != nil || n <= 0 {
272			return 0, fmt.Errorf("invalid --since %q: expected positive integer followed by d/w/m", s)
273		}
274		switch s[len(s)-1] {
275		case 'd':
276			return time.Duration(n) * 24 * time.Hour, nil
277		case 'w':
278			return time.Duration(n) * 7 * 24 * time.Hour, nil
279		case 'm':
280			return time.Duration(n) * 30 * 24 * time.Hour, nil
281		default:
282			return 0, fmt.Errorf("invalid --since suffix %q: use d (days), w (weeks), or m (months)", string(s[len(s)-1]))
283		}
284	}
