336	func analyzeWriteCSV(w io.Writer, dims []string, rows []analyzeResultRow) error {
337		cw := csv.NewWriter(w)
338		headers := make([]string, 0, len(dims)+len(analyzeAggHeaders))
339		headers = append(headers, dims...)
340		headers = append(headers, analyzeAggHeaders...)
341		if err := cw.Write(headers); err != nil {
342			return err
343		}
344		for _, r := range rows {
345			row := make([]string, 0, len(headers))
346			for _, d := range dims {
347				row = append(row, r.Dimensions[d])
348			}
349			row = append(row, analyzeAggValues(r)...)
350			if err := cw.Write(row); err != nil {
351				return err
352			}
353		}
354		cw.Flush()
355		return cw.Error()
356	}
