212	func renderTierSuccessTable(cmd *cobra.Command, rows []tierSuccessRow) error {
213		out := cmd.OutOrStdout()
214		fmt.Fprintf(out, "%-40s  %8s  %9s  %12s  %12s  %14s  %14s  %14s  %s\n",
215			"TIER", "ATTEMPTS", "SUCCESSES", "SUCCESS_RATE", "AVG_COST_USD", "WASTED_COST", "EFFECTIVE_COST", "AVG_DURATION_MS", "FAILURE_MODES")
216		for _, r := range rows {
217			fmt.Fprintf(out, "%-40s  %8d  %9d  %12s  %12s  %14s  %14s  %14.1f  %s\n",
218				truncateTier(r.Tier, 40),
219				r.Attempts,
220				r.Successes,
221				fmt.Sprintf("%.3f", r.SuccessRate),
222				fmt.Sprintf("%.4f", r.AvgCostUSD),
223				fmt.Sprintf("%.4f", r.WastedCostUSD),
224				fmt.Sprintf("%.4f", r.EffectiveCostUSD),
225				r.AvgDurationMS,
226				formatFailureModes(r.FailureModes),
227			)
228		}
229		return nil
230	}
