232	// formatFailureModes renders a failure-mode breakdown as a stable, sorted
233	// "mode=count,mode=count" string. Returns "-" when no failure modes were
234	// recorded so the column is never blank.
235	func formatFailureModes(modes map[string]int) string {
236		if len(modes) == 0 {
237			return "-"
238		}
239		keys := make([]string, 0, len(modes))
240		for k := range modes {
241			keys = append(keys, k)
242		}
243		sort.Strings(keys)
244		parts := make([]string, 0, len(keys))
245		for _, k := range keys {
246			parts = append(parts, fmt.Sprintf("%s=%d", k, modes[k]))
247		}
248		return strings.Join(parts, ",")
249	}
