753				FinalTier:         tierKey(g.finalHarness, g.finalModel),
754				FinalHarness:      g.finalHarness,
755			})
756		}
757		sort.Slice(rows, func(i, j int) bool { return rows[i].BeadID < rows[j].BeadID })
