var reModelField = regexp.MustCompile(`(?m)^model=([^\s]+)\s*$`)

// reACMismatchCount extracts the mismatch_count from a review-ac-override event body.
var reACMismatchCount = regexp.MustCompile(`(?m)^mismatch_count=(\d+)\s*$`)

// reACOverrideReason extracts override_reason lines from a review-ac-override event body.
var reACOverrideReason = regexp.MustCompile(`(?m)^override_reason=(.+)\s*$`)

// reAccuracySignal extracts the signal value from a review-accuracy-override event body.
var reAccuracySignal = regexp.MustCompile(`(?m)^signal=([^\s]+)\s*$`)

// extractRowsFromEvents derives one AttemptRow per kind:cost event found in
// b.Events. Each cost event is paired with the immediately following
// kind:execute-bead event to obtain the outcome. Events between the cost and
// execute-bead events are scanned for reviewer telemetry (reviewer model,
// AC-check mismatch count). A final pass over all events applies any
// review-accuracy-override signal to the last row.
func extractRowsFromEvents(b BeadAttemptEvents) []AttemptRow {
	var rows []AttemptRow
	for i, ev := range b.Events {
		if ev.Kind != "cost" {
			continue
		}
		var cost costEventBody
		if err := json.Unmarshal([]byte(ev.Body), &cost); err != nil || cost.AttemptID == "" {
			continue
		}

		// Scan forward to find execute-bead event and collect reviewer telemetry.
		outcome := ""
		reviewerModel := ""
		acMismatchCount := 0
		var overrideReasons []string
		for _, next := range b.Events[i+1:] {
			if next.Kind == "execute-bead" {
				outcome = next.Summary
				break
			}
			if next.Kind == "review" && reviewerModel == "" {
				if m := reModelField.FindStringSubmatch(next.Body); m != nil {
					reviewerModel = m[1]
				}
			}
			if next.Kind == "review-ac-override" {
				if m := reACMismatchCount.FindStringSubmatch(next.Body); m != nil {
					if n, err := parseInt(m[1]); err == nil {
						acMismatchCount += n
					}
				}
				for _, m := range reACOverrideReason.FindAllStringSubmatch(next.Body, -1) {
					overrideReasons = append(overrideReasons, m[1])
				}
			}
		}

		tsEnd := ""
		if !ev.CreatedAt.IsZero() {
			tsEnd = ev.CreatedAt.UTC().Format(time.RFC3339)
		}
		// Approximate ts_start from ts_end and duration.
		tsStart := ""
		if !ev.CreatedAt.IsZero() && cost.DurationMS > 0 {
			start := ev.CreatedAt.UTC().Add(-time.Duration(cost.DurationMS) * time.Millisecond)
			tsStart = start.Format(time.RFC3339)
		}

		total := cost.TotalTokens
		if total == 0 {
			total = cost.InputTokens + cost.OutputTokens
		}

		row := AttemptRow{
			SchemaVersion:           SchemaVersion,
			AttemptID:               cost.AttemptID,
			BeadID:                  b.BeadID,
			SpecID:                  b.SpecID,
			TSStart:                 tsStart,
			TSEnd:                   tsEnd,
			Model:                   cost.Model,
			Harness:                 cost.Harness,
			Provider:                cost.Provider,
			Outcome:                 outcome,
			ExitCode:                cost.ExitCode,
			CostUSD:                 cost.CostUSD,
			DurationMS:              cost.DurationMS,
			InputTokens:             cost.InputTokens,
			OutputTokens:            cost.OutputTokens,
			TotalTokens:             total,
			ReviewerModel:           reviewerModel,
			ReviewerACMismatchCount: acMismatchCount,
			ReviewerOverrideReasons: overrideReasons,
			ReviewerAccuracySignal:  "unknown",
		}
		rows = append(rows, row)
	}

	// Final pass: apply review-accuracy-override signal to the last row, if any.
	if len(rows) > 0 {
		for _, ev := range b.Events {
			if ev.Kind == "review-accuracy-override" {
				if m := reAccuracySignal.FindStringSubmatch(ev.Body); m != nil {
					rows[len(rows)-1].ReviewerAccuracySignal = m[1]
				}
				break
			}
		}
	}

	return rows
}

// parseInt parses a decimal integer string.
func parseInt(s string) (int, error) {
	var n int
	for _, c := range s {
		if c < '0' || c > '9' {
			return 0, fmt.Errorf("invalid digit %q", c)
		}
		n = n*10 + int(c-'0')
	}
	return n, nil
}

