// acCheckMismatch describes one AC where the reviewer's grade contradicts the
// mechanical ac-check.json result.
type acCheckMismatch struct {
	AC             int
	ACCheckResult  string // "pass" or "fail"
	ReviewerGrade  string // reviewer's grade string
	OverrideReason string // evidence/reason from reviewer per-AC, if any
}

// detectACCheckMismatches compares a reviewer's per-AC grades against the
// mechanical ac-check.json items. A mismatch is recorded when:
//   - ac-check result is "fail" but reviewer grades the AC as "pass"
//   - ac-check result is "pass" but reviewer grades the AC as "fail"
//
// AC items with result "needs_judgment" or "error" are skipped (they require
// human adjudication by design). Returns nil when acCheckJSON is empty or
// unparseable.
func detectACCheckMismatches(acCheckJSON string, perAC []ReviewAC) []acCheckMismatch {
	if acCheckJSON == "" || len(perAC) == 0 {
		return nil
	}
	// Inline parse of the ac-check.json items — only need ac number + result.
	var acCheck struct {
		Items []struct {
			AC     int    `json:"ac"`
			Result string `json:"result"`
		} `json:"items"`
	}
	if err := json.Unmarshal([]byte(acCheckJSON), &acCheck); err != nil {
		return nil
	}
	// Build a map of ac-number → result for fast lookup.
	mechanicalResult := make(map[int]string, len(acCheck.Items))
	for _, item := range acCheck.Items {
		mechanicalResult[item.AC] = item.Result
	}

	var mismatches []acCheckMismatch
	for _, pac := range perAC {
		mech, ok := mechanicalResult[pac.Number]
		if !ok {
			continue
		}
		// Only compare deterministic mechanical results (pass/fail).
		if mech != "pass" && mech != "fail" {
			continue
		}
		reviewerGrade := strings.ToLower(strings.TrimSpace(pac.Grade))
		// Normalise reviewer grade to pass/fail.
		reviewerPass := reviewerGrade == "pass"
		reviewerFail := reviewerGrade == "fail" || reviewerGrade == "block"
		if !reviewerPass && !reviewerFail {
			continue
		}
		mechFail := mech == "fail"
		if mechFail != reviewerFail {
			mm := acCheckMismatch{
				AC:            pac.Number,
				ACCheckResult: mech,
				ReviewerGrade: pac.Grade,
			}
			// The reviewer's evidence string may contain the override reason.
			if pac.Evidence != "" {
				mm.OverrideReason = strings.TrimSpace(pac.Evidence)
			}
			mismatches = append(mismatches, mm)
		}
	}
	return mismatches
}

// formatACOverrideEventBody renders the body for a kind:review-ac-override event.
func formatACOverrideEventBody(mismatches []acCheckMismatch) string {
	var b strings.Builder
	fmt.Fprintf(&b, "mismatch_count=%d\n", len(mismatches))
	for _, m := range mismatches {
		fmt.Fprintf(&b, "ac=%d ac_check=%s reviewer_grade=%s\n", m.AC, m.ACCheckResult, m.ReviewerGrade)
		if m.OverrideReason != "" {
			first := m.OverrideReason
			if idx := strings.IndexByte(first, '\n'); idx >= 0 {
				first = first[:idx]
			}
			fmt.Fprintf(&b, "override_reason=%s\n", first)
		}
	}
	return strings.TrimRight(b.String(), "\n")
}

