// lastReviewVerdictFromEvents returns the Summary of the most recent "review"
// event (case-insensitive trim), or "" if no review event exists.
func lastReviewVerdictFromEvents(events []BeadEvent) string {
	for i := len(events) - 1; i >= 0; i-- {
		if events[i].Kind == "review" {
			return strings.TrimSpace(events[i].Summary)
		}
	}
	return ""
}

// reviewAccuracyOverrideBody renders the body for a kind:review-accuracy-override event.
func reviewAccuracyOverrideBody(verdictWas, operatorAction, reason, signal string) string {
	var b strings.Builder
	fmt.Fprintf(&b, "verdict_was=%s\n", verdictWas)
	fmt.Fprintf(&b, "operator_action=%s\n", operatorAction)
	if reason != "" {
		fmt.Fprintf(&b, "reason=%s\n", reason)
	}
	fmt.Fprintf(&b, "signal=%s", signal)
	return b.String()
}

// isFakeWorkReopenReason returns true when the reopen reason indicates the
