import (
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/testutils"
)

// TestReviewAccuracy_OperatorOverride_EmitsEvent verifies that Store.Close
// emits a kind:review-accuracy-override event when the operator manually
// closes a bead that was previously reviewer-BLOCKed (false positive signal).
func TestReviewAccuracy_OperatorOverride_EmitsEvent(t *testing.T) {
	repo := testutils.NewFixtureRepo(t, "minimal")
	store := bead.NewStore(repo.DDXDir())

	b := &bead.Bead{
		ID:     "ddx-acc-override-01",
		Title:  "Test reviewer accuracy override",
		Status: bead.StatusOpen,
	}
	if err := store.Create(b); err != nil {
		t.Fatalf("Create: %v", err)
	}

	// Simulate reviewer appending a BLOCK verdict event.
	if err := store.AppendEvent(b.ID, bead.BeadEvent{
		Kind:      "review",
		Summary:   "BLOCK",
		Body:      "fake work detected",
		Source:    "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	}); err != nil {
		t.Fatalf("AppendEvent review BLOCK: %v", err)
	}

	// Operator manually closes the bead.
	if err := store.Close(b.ID); err != nil {
		t.Fatalf("Close: %v", err)
	}

	events, err := store.Events(b.ID)
	if err != nil {
		t.Fatalf("Events: %v", err)
	}

	var found *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "review-accuracy-override" {
			found = &events[i]
			break
		}
	}
	if found == nil {
		t.Fatal("expected kind:review-accuracy-override event, none found")
	}
	if !strings.Contains(found.Body, "verdict_was=BLOCK") {
		t.Errorf("event body missing verdict_was=BLOCK: %q", found.Body)
	}
	if !strings.Contains(found.Body, "operator_action=close") {
		t.Errorf("event body missing operator_action=close: %q", found.Body)
	}
	if !strings.Contains(found.Body, "signal=override_fp") {
		t.Errorf("event body missing signal=override_fp: %q", found.Body)
	}
}

// TestReviewAccuracy_OperatorReopen_AfterApprove_EmitsFNEvent verifies that
// Store.Reopen emits a kind:review-accuracy-override event with signal=override_fn
// when the operator reopens a reviewer-APPROVEd bead with a fake-work reason.
func TestReviewAccuracy_OperatorReopen_AfterApprove_EmitsFNEvent(t *testing.T) {
	repo := testutils.NewFixtureRepo(t, "minimal")
	store := bead.NewStore(repo.DDXDir())

	b := &bead.Bead{
		ID:     "ddx-acc-reopen-fn",
		Title:  "Test reviewer FN override",
		Status: bead.StatusOpen,
	}
	if err := store.Create(b); err != nil {
		t.Fatalf("Create: %v", err)
	}

	// Simulate reviewer APPROVE and close.
	if err := store.AppendEvent(b.ID, bead.BeadEvent{
		Kind:      "review",
		Summary:   "APPROVE",
		Body:      "all ACs verified",
		Source:    "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	}); err != nil {
		t.Fatalf("AppendEvent review APPROVE: %v", err)
	}

	// Simulate closing the bead (use internal transition to avoid closure gate).
	if err := store.Update(b.ID, func(bb *bead.Bead) {
		bb.Status = bead.StatusClosed
	}); err != nil {
		t.Fatalf("Update to closed: %v", err)
	}

	// Operator reopens with a fake-work reason.
	if err := store.Reopen(b.ID, "fake-work: agent hallucinated the diff", ""); err != nil {
		t.Fatalf("Reopen: %v", err)
	}

	events, err := store.Events(b.ID)
	if err != nil {
		t.Fatalf("Events: %v", err)
	}

	var found *bead.BeadEvent
	for i := range events {
		if events[i].Kind == "review-accuracy-override" {
			found = &events[i]
			break
		}
	}
	if found == nil {
		t.Fatal("expected kind:review-accuracy-override event, none found")
	}
	if !strings.Contains(found.Body, "verdict_was=APPROVE") {
		t.Errorf("event body missing verdict_was=APPROVE: %q", found.Body)
	}
	if !strings.Contains(found.Body, "operator_action=reopen") {
		t.Errorf("event body missing operator_action=reopen: %q", found.Body)
	}
	if !strings.Contains(found.Body, "signal=override_fn") {
		t.Errorf("event body missing signal=override_fn: %q", found.Body)
	}
}

// TestReviewAccuracy_NoEvent_WhenNoBlockVerdict verifies that Store.Close does
// NOT emit a review-accuracy-override event when there is no prior BLOCK verdict.
func TestReviewAccuracy_NoEvent_WhenNoBlockVerdict(t *testing.T) {
	repo := testutils.NewFixtureRepo(t, "minimal")
	store := bead.NewStore(repo.DDXDir())

	b := &bead.Bead{
		ID:     "ddx-acc-no-override",
		Title:  "No prior BLOCK verdict",
		Status: bead.StatusOpen,
	}
	if err := store.Create(b); err != nil {
		t.Fatalf("Create: %v", err)
	}

	// Close without any prior review events.
	if err := store.Close(b.ID); err != nil {
		t.Fatalf("Close: %v", err)
	}

	events, err := store.Events(b.ID)
	if err != nil {
		t.Fatalf("Events: %v", err)
	}
	for _, ev := range events {
		if ev.Kind == "review-accuracy-override" {
			t.Errorf("unexpected review-accuracy-override event when no BLOCK verdict present")
		}
	}
}

