1461	// acCheckMismatch describes one AC where the reviewer's grade contradicts the
1462	// mechanical ac-check.json result.
1463	type acCheckMismatch struct {
1464		AC             int
1465		ACCheckResult  string // "pass" or "fail"
1466		ReviewerGrade  string // reviewer's grade string
1467		OverrideReason string // evidence/reason from reviewer per-AC, if any
1468	}
1469	
1470	// detectACCheckMismatches compares a reviewer's per-AC grades against the
1471	// mechanical ac-check.json items. A mismatch is recorded when:
1472	//   - ac-check result is "fail" but reviewer grades the AC as "pass"
1473	//   - ac-check result is "pass" but reviewer grades the AC as "fail"
1474	//
1475	// AC items with result "needs_judgment" or "error" are skipped (they require
1476	// human adjudication by design). Returns nil when acCheckJSON is empty or
1477	// unparseable.
1478	func detectACCheckMismatches(acCheckJSON string, perAC []ReviewAC) []acCheckMismatch {
1479		if acCheckJSON == "" || len(perAC) == 0 {
1480			return nil
1481		}
1482		// Inline parse of the ac-check.json items — only need ac number + result.
1483		var acCheck struct {
1484			Items []struct {
1485				AC     int    `json:"ac"`
1486				Result string `json:"result"`
1487			} `json:"items"`
1488		}
1489		if err := json.Unmarshal([]byte(acCheckJSON), &acCheck); err != nil {
1490			return nil
1491		}
1492		// Build a map of ac-number → result for fast lookup.
1493		mechanicalResult := make(map[int]string, len(acCheck.Items))
1494		for _, item := range acCheck.Items {
1495			mechanicalResult[item.AC] = item.Result
1496		}
1497	
1498		var mismatches []acCheckMismatch
1499		for _, pac := range perAC {
1500			mech, ok := mechanicalResult[pac.Number]
1501			if !ok {
1502				continue
1503			}
1504			// Only compare deterministic mechanical results (pass/fail).
1505			if mech != "pass" && mech != "fail" {
1506				continue
1507			}
1508			reviewerGrade := strings.ToLower(strings.TrimSpace(pac.Grade))
1509			// Normalise reviewer grade to pass/fail.
1510			reviewerPass := reviewerGrade == "pass"
1511			reviewerFail := reviewerGrade == "fail" || reviewerGrade == "block"
1512			if !reviewerPass && !reviewerFail {
1513				continue
1514			}
1515			mechFail := mech == "fail"
1516			if mechFail != reviewerFail {
1517				mm := acCheckMismatch{
1518					AC:            pac.Number,
1519					ACCheckResult: mech,
1520					ReviewerGrade: pac.Grade,
1521				}
1522				// The reviewer's evidence string may contain the override reason.
1523				if pac.Evidence != "" {
1524					mm.OverrideReason = strings.TrimSpace(pac.Evidence)
1525				}
1526				mismatches = append(mismatches, mm)
1527			}
1528		}
1529		return mismatches
1530	}
