// TestReviewAccuracy_ACCheckDisagreement_RecordedInMetrics verifies that
// detectACCheckMismatches correctly identifies per-AC grade disagreements and
// that BackfillFromEvents populates ReviewerACMismatchCount and
// ReviewerOverrideReasons from the emitted review-ac-override event body.
func TestReviewAccuracy_ACCheckDisagreement_RecordedInMetrics(t *testing.T) {
	// AC check says AC1=pass, AC2=fail; reviewer says AC1=fail, AC2=pass.
	acCheckJSON := `{"items":[{"ac":1,"result":"pass"},{"ac":2,"result":"fail"}]}`
	perAC := []ReviewAC{
		{Number: 1, Grade: "fail", Evidence: "test binary missing"},
		{Number: 2, Grade: "pass", Evidence: "file exists"},
	}
	mismatches := detectACCheckMismatches(acCheckJSON, perAC)
	if len(mismatches) != 2 {
		t.Fatalf("detectACCheckMismatches: want 2 mismatches, got %d", len(mismatches))
	}

	eventBody := formatACOverrideEventBody(mismatches)
	if !strings.Contains(eventBody, "mismatch_count=2") {
		t.Errorf("event body missing mismatch_count=2: %q", eventBody)
	}
	if !strings.Contains(eventBody, "override_reason=") {
		t.Errorf("event body missing override_reason lines: %q", eventBody)
	}

	// Verify BackfillFromEvents parses the emitted event body into AttemptRow fields.
	now := time.Date(2026, 1, 1, 12, 0, 0, 0, time.UTC)
	costBody := `{"attempt_id":"acc-mismatch-test-01","harness":"claude","provider":"anthropic","model":"claude-sonnet-4-6","input_tokens":500,"output_tokens":200,"total_tokens":700,"cost_usd":0.25,"duration_ms":30000,"exit_code":0}`
	events := []bead.BeadEvent{
		{Kind: "cost", Body: costBody, CreatedAt: now},
		{Kind: "review-ac-override", Summary: "2 AC-check mismatch(es)", Body: eventBody, Source: "ddx agent execute-loop", CreatedAt: now.Add(5 * time.Second)},
		{Kind: "execute-bead", Summary: "review_block", CreatedAt: now.Add(10 * time.Second)},
	}

	dir := t.TempDir()
	beads := []attemptmetrics.BeadAttemptEvents{
		{BeadID: "ddx-acc-mismatch-01", SpecID: "TEST-001", Events: events},
	}

	added, err := attemptmetrics.BackfillFromEvents(dir, beads)
	if err != nil {
		t.Fatalf("BackfillFromEvents: %v", err)
	}
	if added != 1 {
		t.Fatalf("expected 1 row added, got %d", added)
	}

	rows, err := attemptmetrics.LoadRows(dir)
	if err != nil {
		t.Fatalf("LoadRows: %v", err)
	}
	if len(rows) != 1 {
		t.Fatalf("expected 1 row, got %d", len(rows))
	}
	row := rows[0]
	if row.ReviewerACMismatchCount != 2 {
		t.Errorf("reviewer_acmismatch_count=%d, want 2", row.ReviewerACMismatchCount)
	}
	if len(row.ReviewerOverrideReasons) == 0 {
		t.Error("reviewer_override_reasons should be non-empty")
	}
}

