		{SchemaVersion: 1, AttemptID: "r3", BeadID: "b3", ReviewerModel: "reviewer-A", ReviewerAccuracySignal: "unknown", Outcome: "task_succeeded"},
		// reviewer-B: 2 attempts, 0 false-positive, 1 false-negative override
		{SchemaVersion: 1, AttemptID: "r4", BeadID: "b4", ReviewerModel: "reviewer-B", ReviewerAccuracySignal: "override_fn", Outcome: "task_succeeded"},
		{SchemaVersion: 1, AttemptID: "r5", BeadID: "b5", ReviewerModel: "reviewer-B", ReviewerAccuracySignal: "unknown", Outcome: "review_block"},
	})

	out := runAnalyze(t, dir, "--by", "reviewer-model")

	if !strings.Contains(out, "reviewer-A") {
		t.Errorf("expected reviewer-A in output:\n%s", out)
	}
	if !strings.Contains(out, "reviewer-B") {
		t.Errorf("expected reviewer-B in output:\n%s", out)
	}
	// fp_rate and fn_rate columns should appear in the header
	if !strings.Contains(out, "fp_rate") {
		t.Errorf("expected fp_rate column in output:\n%s", out)
	}
	if !strings.Contains(out, "fn_rate") {
		t.Errorf("expected fn_rate column in output:\n%s", out)
	}
	// reviewer-A fp_rate = 1/3 ≈ 0.3333; reviewer-B fn_rate = 1/2 = 0.5000
	if !strings.Contains(out, "0.3333") {
		t.Errorf("expected reviewer-A fp_rate=0.3333 in output:\n%s", out)
	}
	if !strings.Contains(out, "0.5000") {
		t.Errorf("expected reviewer-B fn_rate=0.5000 in output:\n%s", out)
	}
}
